var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"큭! 이러다 전복되겠어! 후퇴해!","JPN":"くっ！　このままだと転覆してしまう！　後退しろ！","ENG":"Kgh! The ship's going to turn over! Retreat!","TWN":"唔！這樣下去會全軍覆沒，撤退！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"두고 보자, 샤크스!","JPN":"覚えておけよ、シャークス！","ENG":"This isn't over, Sharks!","TWN":"走著瞧，大白鯊海盜團！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_18"},{"id":"L5_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"캬하핫- 벌써 전부 나가떨어진 건가? 시시하긴.","JPN":"キャハハッ、もう全部諦めたのか？　つまんないね。","ENG":"Kya hah hah! Are they already gone? Lame.","TWN":"哈哈哈，這麼快就撤退啦？真沒意思。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"꺄하하- 너무 쉬운데요?","JPN":"キャハハッ、簡単すぎますね。","ENG":"Kya hah hah. It's too easy!","TWN":"哈哈哈，得來全不費工夫呢？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"뭔가 이상하지 않아?","JPN":"何かおかしくない？","ENG":"Something's weird.","TWN":"不覺得有些奇怪嗎？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"싸우는 동안 침식체가 하나도 보이지 않았어.","JPN":"戦っている間に侵食体が一匹も出なかった。","ENG":"I didn't see a single C.O. while we were fighting.","TWN":"剛剛和其他人交手的時候，連一隻侵蝕體都沒有看到。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"어라? 그러게요.","JPN":"あれ？　そうですね。","ENG":"Huh? Come to think of it, you're right.","TWN":"喔？說的也是。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"저희가 우연히 다 피해서 온 거 아닐까요?","JPN":"私たちが運よく全部避けてきたとか？","ENG":"Maybe we just happened to avoid all of them?","TWN":"會不會是都剛好沒遇到？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"검은 범람이 오면 항상 격벽 주위엔 침식체가 들끓었다고.","JPN":"黒い氾濫が来るといつも隔壁の周りには侵食体がうじゃうじゃいたよ。","ENG":"With the Black Flood, the bulwark should be surrounded by C.O.s.","TWN":"每當發生黑色洪災時，隔離牆周圍總是會佈滿侵蝕體。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그런데 막상 바다 한가운덴 아무것도 없는 게 말이 돼?","JPN":"なのにいざ海のど真ん中には何もないのってありえないだろ？","ENG":"But it doesn't make sense that there's none of them in the middle of the ocean.","TWN":"但現在我們可是在海中央，連一隻侵蝕體都沒有說得過去嗎？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"이상하게 생각할 필요 없어. 좋은 게 좋은 거지.","JPN":"深く考える必要はない。結果オーライだ。","ENG":"Don't overthink it. It's a good thing.","TWN":"別胡思亂想，就算我們幸運吧。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"이대로 심해역까지 가서 에이버리의 함선을 찾기만 하면 끝…","JPN":"このまま深海域まで行ってエイバリーの艦船を見つけさえすれば終わ……","ENG":"We'll continue on to the deep sea area and find Avery's ship–","TWN":"就這樣去到深海域，找到艾維利的艦船…"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"뭐죠? 배에 뭔가 걸리는 소리가 났는데요?","JPN":"あれ？　船に何か引っかかる音がしましたよ？","ENG":"Huh? Did something get caught on the ship?","TWN":"嗯？好像有什麼東西勾到船？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"배가 멈췄잖아? 해조류에 엉켰나?","JPN":"船が止まった？　海藻が絡まったのか？","ENG":"The ship's stopped. Is it entangled in seaweed or something?","TWN":"船怎麼停啦？是被海草纏住嗎？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"내가 밑으로 가서 확인해볼게.","JPN":"あたしが下に行って見てくる。","ENG":"I'll go down and check.","TWN":"我下去看看。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"네? 소냐, 잠깐만요! 뭐가 있을 줄 알고…!","JPN":"はい？　ソーニャ、待って！　何があるかわからないじゃないですか……！","ENG":"Huh? Sonya, wait! You don't know what's down there...!","TWN":"什麼？索妮雅，等等！下面不知道有什麼…！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"…수면 아래가 하나도 안 보이는데요? 괜찮을까요?","JPN":"……水面の下が何も見えませんよ？　大丈夫でしょうか？","ENG":"...I can't see anything in the water. Will she be okay?","TWN":"…水下面什麼也看不見？不會出事吧？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"뭐, 소냐라면 어련히 알아서 해결하겠지.","JPN":"まあ、ソーニャなら何とか解決できるだろう。","ENG":"It's Sonya. She can take care of herself.","TWN":"沒事，索妮雅會自己想辦法的。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"기왕 이렇게 된 거, 난 누워서 윙스타 근황 중계나…","JPN":"こうなったからには、あたしは寝転んでウィングスターでも……","ENG":"Well, since we're stopping, I'll just lie down and do a live stream on Wing-sta–","TWN":"在她回來之前我就先躺下來滑一下…"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"우왓?!","JPN":"うわっ！？","ENG":"Whoa?!","TWN":"哇？！"},"stage":{"bg":"FRONTBAY_01","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"꺄아아아!","JPN":"きゃあああ！","ENG":"Kyaaaa!","TWN":"啊啊啊啊！"},"stage":{"bg":"FRONTBAY_01","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"뭐, 뭐야? 이 괴상하게 생겨 먹은 촉수는?!","JPN":"な、何？　この怪しい触手は！？","ENG":"W-what's this? What are these creepy tentacles?!","TWN":"這…這是什麼？長得很詭異的觸手？!"},"stage":{"bg":"FRONTBAY_01","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"으와아아아!! 우와아아!!","JPN":"うわあああ！！　うわああ！！","ENG":"Waaaahh!! Ahhhh!!","TWN":"呃啊啊啊啊！！啊啊啊！！"},"stage":{"bg":"FRONTBAY_01","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"크윽…? 안 풀려?","JPN":"くうっ……！　解けない？","ENG":"Kgh...! I can't get out?","TWN":"唔…？解不開？"},"stage":{"bg":"FRONTBAY_01","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L33_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"야! 탈리! 비명 그만 지르고 이것부터 떼봐!","JPN":"こら！　タリー！　悲鳴はもうやめてこれを外せ！","ENG":"Hey, Tallie! Stop screaming and get this off of me!","TWN":"喂！塔莉！別再叫了，先把他從我身上拿下來！"},"stage":{"bg":"FRONTBAY_01","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"무리에요, 선장님! 그렇게 경박한 모습을 하고 있으면 눈을 뜰 수가 없다고요!","JPN":"無理です、船長！　そんなはしたない恰好をしていると目を開けられません！","ENG":"I can't, Captain! You look so obscene, I can't keep my eyes open!","TWN":"我做不到，船長！你現在長得好噁心，我沒看法看！"},"stage":{"bg":"FRONTBAY_01","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"너 방금 열 척이나 되는 배들을 웃으면서 터뜨렸잖아! 왜 갑자기 순진한 척 구는 건데?!","JPN":"お前今さっき十隻の船を笑いながら爆破させたじゃん！　何でいきなり無邪気なふりをするんだ！？","ENG":"You were just laughing as you blew up ten ships! Why are you acting innocent all of a sudden?!","TWN":"你剛剛還笑瞇瞇地炸掉十艘船，現在給我裝什麼天真無辜？"},"stage":{"bg":"FRONTBAY_01","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"제 문제가 아니라 선장님 몸이 그렇게 생겨먹은 게 잘못이라고요!","JPN":"私が悪いのではなく、船長の体が悪いのです！","ENG":"It's not me! Why does your body have to look like that?!","TWN":"這不能怪我，都是船長的錯，誰叫你要長成那樣的！"},"stage":{"bg":"FRONTBAY_01","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"대체 무슨 뜻이야 그거?!","JPN":"いったいどういう意味だ、それ！？","ENG":"What does that mean?!","TWN":"你到底在說什麼？！"},"stage":{"bg":"FRONTBAY_01","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"아무튼 알아서 좀 해보세요! 선장님은 A급 카운터잖아요!","JPN":"とにかく自分で何とかしてください！　船長はA級カウンターじゃないですか！","ENG":"Just, take care of it, somehow! You're a Grade A Counter!","TWN":"總之你自己看著辦吧！船長不是A級制裁者嗎！"},"stage":{"bg":"FRONTBAY_01","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"아니, 이거 너무 미끈거려서 붙잡힌 채로는 힘을 쓸 수가…","JPN":"いいや、これヌルヌルしすぎで、捕まれた状態では力が出ない……","ENG":"This is too slippery, I can't do anything while restrained...","TWN":"不行，他好滑，我抓不住…"},"stage":{"bg":"FRONTBAY_01","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"큭, 이대로 가다간 옷이…!","JPN":"くっ、このままでは服が……！","ENG":"Kgh, my clothes are gonna–!","TWN":"唔，再這樣下去我的衣服要…！"},"stage":{"bg":"FRONTBAY_01","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"케헥! 풀려났다…!","JPN":"ぐはっ！　抜け出した……！","ENG":"Keh! I'm free...!","TWN":"呃咳！終於解開了…！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L46_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"아, 미안.","JPN":"あ、ごめん。","ENG":"Ah, sorry.","TWN":"抱歉。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"이 촉수 자르면 안 되는 상황이었나?","JPN":"この触手、切ってはならん状況だった？","ENG":"Was I not supposed to cut the tentacles?","TWN":"剛剛是不是不該砍掉那根觸手？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"그게 무슨 소리야? 선장이 위기에 빠졌으면 당연히 도와줘야지.","JPN":"何言っているんだ？　船長がピンチになっているんだ、助けて当然だろ。","ENG":"What are you talking about? Your captain was in danger, of course you were supposed to help.","TWN":"胡說什麼？船長陷入危險，你當然要出手。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"아니… 어디선가 엄청 실망하는 듯한 기색이 느껴져서… 기분 탓이겠지?","JPN":"いや……どこからか凄くガッカリしたような気配がして……気のせいか？","ENG":"It's just... I felt a sense of disappointment from somewhere... I guess it's nothing.","TWN":"那個…好像有種很可惜的感覺…應該是我的錯覺吧？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"소냐?! 살아있었어요?","JPN":"ソーニャ！？　生きていました？","ENG":"Sonya! You're alive!","TWN":"索妮雅？你還活著！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"난 괜찮아.","JPN":"あたしは大丈夫。","ENG":"I'm fine.","TWN":"我沒事。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"배 상태만 확인하려다 너무 어두워서 돌아왔더니 선장이 촉수를 가지고 탈의행위를….","JPN":"船の状態を確認しようとしたけど、暗すぎて戻ってきたら船長が触手で脱衣行為を……","ENG":"I was trying to check the ship, and it got dark, so I came back up only to see the captain trying to take her clothes off with tentacles...","TWN":"我本來想去查看船的狀況，但周圍太暗只好先回來。然後就看見船長抱著觸手脫衣服…"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"내가 아니라 저것들이 날 갑자기 붙잡은 거거든!","JPN":"あたしじゃなくて、あいつらが勝手にあたしを捕まえたよ！","ENG":"That wasn't my doing! Those things grabbed ME!","TWN":"是觸手突然纏著我，不是我抱著他！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L7_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"하지만 물 속에 들어간 소냐를 전혀 건드리지 않다니, 의외네요.","JPN":"でも水の中に潜っていたソーニャには手を出さないとは、意外ですね。","ENG":"But it's weird that they didn't even touch Sonya, and you were underwater.","TWN":"但奇怪的是，他完全沒有去招惹還在水裡的索妮雅。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"아니면 취향을 타는 까다로운 촉수인가?","JPN":"それとも好みがハッキリしている触手なのかな？","ENG":"Maybe the tentacles have a specific taste?","TWN":"還是說，這個麻煩的觸手有自己的喜好？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"방금 순진한 척하면서 나 놀린 거지?","JPN":"今何も知らないふりをしながら、あたしをからかってない？","ENG":"Did you just make fun of me while acting innocent?","TWN":"你這是在逗我笑嗎？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"꺄아! 촉수가 또 여러 개 튀어나왔다!","JPN":"きゃあ！　また何本も触手が出ました！","ENG":"Kyah! More tentacles!","TWN":"哇啊！又有好多個觸手從水裡蹦出來！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"좋아! 촉수! 이번엔 탈리 녀석을 엉망진창으로 만들어버려!","JPN":"よっしゃ！　触手！　今度こそタリーのやつを滅茶苦茶にしてやれ！","ENG":"Good! Tentacles! This time, aim for Tallie! Mess her up!","TWN":"非常好！觸手們！這次去糾纏塔莉吧！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"너무해요! 선장님!","JPN":"酷いです！　船長！","ENG":"How could you, Captain?!","TWN":"船長，你好壞！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"그런데 대체 뭘까요? 저 기분 나쁘게 꿈틀거리는 문어다리는?","JPN":"でもいったいなんでしょう？　あの気持ち悪いタコの足は。","ENG":"But really, what were those squirming octopus tentacles?","TWN":"不過，這到底是什麼？這些令人毛骨悚然的章魚角？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"잠깐, 문어라고…?","JPN":"ちょっと、タコ...…？","ENG":"Wait, octopus...?","TWN":"等等，章魚…？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"설마 저거… 크라켄인가?","JPN":"まさか、あれ……クラーケンか？","ENG":"Is that... Kraken?","TWN":"這個…該不會是克拉肯吧？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"헤엑! 크라켄?! 그 4종 침식체요?!","JPN":"ひいっ！　クラーケン！？　あの第4種侵食体ですか！？","ENG":"Heek! Kraken?! The Category 4 C.O.?!","TWN":"什麼！克拉肯？！那個4類侵蝕體？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"오, 바다에 침식체들이 하나도 안 보이던 이유가 크라켄의 텃세 때문이라면 납득은 되는구만.","JPN":"お、海に侵食体が全然見えなかった理由も、クラーケンのせいだと思うと納得できる。","ENG":"Oh, it'd make sense that there are no C.O.s around if it's because of Kraken's territorial attitude.","TWN":"喔，那我大概知道海裡看不到其他侵蝕體的原因了。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"크기만 하고 별로 맛있어 보이진 않네.","JPN":"大きいだけで別に美味しくはなさそうね。","ENG":"It's just big and doesn't even look that tasty.","TWN":"他就是體型大而已，看起來不怎麼好吃。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"지금 그런 걸로 실망할 때가 아니잖아요!!","JPN":"今はそんなことでがっかりしている場合じゃないでしょう！！","ENG":"This isn't the time for you to be disappointed at that!!","TWN":"現在不是因為這種事失望的時候！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"어쩌죠? 어떻게 도망치죠?!","JPN":"どうしましょう？　どうやって逃げればいいんですか！？","ENG":"What do we do? How do we escape?!","TWN":"怎麼辦？要逃跑嗎？！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"도망칠 수 없으면 즐기라는 말 알아?","JPN":"逃げられないなら楽しめ、って言葉知っているか？","ENG":"Do you know the saying, \\"If you can't avoid it, enjoy it\\"?","TWN":"你知道有句話說，無法逃的話，那就享受它嗎？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"못 도망치면 바다망령이 된다는 건 아는데요!","JPN":"逃げなければ海の亡霊になるのは知っています！","ENG":"I do know that we'll end up as pirate ghosts if we don't get out of here!","TWN":"我只知道，如果逃不掉的話，我們就會葬身海底！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"엄호해줘, 탈리.","JPN":"援護して、タリー。","ENG":"Cover me, Tallie.","TWN":"掩護我，塔莉。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"저 문어다릴 통구이로 먹을 수 있는지 시험해보자고.","JPN":"あのタコの足、丸焼きで食べられるのか試してみよう。","ENG":"Let's see if we can grill those tentacles.","TWN":"我試試看能不能把整個章魚腳吃掉。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};